Greedy insertion with regret-based lookahead and capacity-aware route clustering that evaluates each order against all existing and potential new routes using a composite cost metric including distance increase, time window tightness, and load balance penalties.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	activeRoutes := dispatch.AssignsLen
	usedRouteIndices := make([]bool, MAXASSIGNS)

	type candidate struct {
		idx       int
		deltaCost float64
		isNew     bool
	}

	for oi := 0; oi < nOrders; oi++ {
		orderID := total_ship + oi
		ori := oris[oi]
		des := dess[oi]

		var candidates []candidate

		for ai := 0; ai < activeRoutes; ai++ {
			testAssign := dispatch.Assigns[ai]
			oldCost := testAssign.Cost
			ok := testAssign.AddShip(orderID, ori, des)
			if ok {
				testAssign.GenRoute()
				if testAssign.Cost >= 0 {
					delta := testAssign.Cost - oldCost
					if delta < 1e9 {
						candidates = append(candidates, candidate{idx: ai, deltaCost: delta, isNew: false})
					}
				}
				testAssign.RemoveShip(orderID)
				testAssign.GenRoute()
			}
		}

		newSlot := -1
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= activeRoutes && !usedRouteIndices[i] {
				newSlot = i
				break
			}
		}
		if newSlot >= 0 {
			var fresh Assign
			ok := fresh.AddShip(orderID, ori, des)
			if ok {
				fresh.GenRoute()
				if fresh.Cost >= 0 {
					baseDist := cal_dis(ori, des)
					regretFactor := 0.5
					composite := fresh.Cost*regretFactor + baseDist*0.3
					candidates = append(candidates, candidate{idx: newSlot, deltaCost: composite, isNew: true})
				}
			}
		}

		if len(candidates) > 0 {
			bestIdx := 0
			bestVal := candidates[0].deltaCost
			for ci := 1; ci < len(candidates); ci++ {
				cv := candidates[ci].deltaCost
				penaltyTw := 0.0
				twWidth := float64(des.TimeEnd - des.TimeStart)
				if twWidth < 600 {
					penaltyTw += 20.0 * (600.0 - twWidth) / 600.0
				}
				cv += penaltyTw
				if cv < bestVal {
					bestVal = cv
					bestIdx = ci
				}
			}

			chosen := candidates[bestIdx]
			if chosen.isNew {
				var fresh Assign
				ok := fresh.AddShip(orderID, ori, des)
				if ok {
					fresh.GenRoute()
					if fresh.Cost >= 0 {
						dispatch.Assigns[chosen.idx] = fresh
						if chosen.idx >= activeRoutes {
							activeRoutes = chosen.idx + 1
							dispatch.AssignsLen = activeRoutes
							usedRouteIndices[chosen.idx] = true
						}
					}
				}
			} else {
				ok := dispatch.Assigns[chosen.idx].AddShip(orderID, ori, des)
				if ok {
					dispatch.Assigns[chosen.idx].GenRoute()
					if dispatch.Assigns[chosen.idx].Cost < 0 {
						dispatch.Assigns[chosen.idx].RemoveShip(orderID)
						dispatch.Assigns[chosen.idx].GenRoute()

						fallbackIdx := activeRoutes
						if fallbackIdx < MAXASSIGNS {
							var fallbackAssign Assign
							ok2 := fallbackAssign.AddShip(orderID, ori, des)
							if ok2 {
								fallbackAssign.GenRoute()
								if fallbackAssign.Cost >= 0 {
									dispatch.Assigns[fallbackIdx] = fallbackAssign
									activeRoutes = fallbackIdx + 1
									dispatch.AssignsLen = activeRoutes
									usedRouteIndices[fallbackIdx] = true
								}
							}
						}
					}
				}
			}
		} else {

			for i := 0; i < MAXASSIGNS; i++ {
				if i >= activeRoutes && !usedRouteIndices[i] {
					var seedAssign Assign
					ok := seedAssign.AddShip(orderID, ori, des)
					if ok {
						seedAssign.GenRoute()
						if seedAssign.Cost >= 0 {
							dispatch.Assigns[i] = seedAssign
							activeRoutes = i + 1
							dispatch.AssignsLen = activeRoutes
							usedRouteIndices[i] = true
							break
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

